const items = $input.all();

const hoy = new Date().toLocaleDateString('es-BO', {
  day: '2-digit', month: '2-digit', year: 'numeric',
  timeZone: 'America/La_Paz'
});

if (!items || items.length === 0) {
  return [{
    json: {
      mensaje: "🏋 <b>REPORTE DE VENCIMIENTOS</b>\n" + hoy +
        "\n\n✅ No hay membresias por vencer ni vencidas hoy.",
      inbox_tipo: "vencimiento",
      inbox_titulo: "Reporte diario de vencimientos - " + hoy,
      inbox_mensaje: "No hay membresias por vencer ni vencidas hoy.",
      inbox_prioridad: "baja"
    }
  }];
}

const porVencer = [];
const vencidas = [];
const inboxLineas = [];

for (const item of items) {
  const d = item.json;
  const dias = Number(d.dias_restantes);
  const nombre = d.fullname || 'Sin nombre';
  const plan = d.plan_nombre || 'Sin plan';
  const fecha = d.fecha_vencimiento || '---';
  const tel = d.contact || 'Sin contacto';

  if (dias >= 0) {
    porVencer.push("⚠ <b>" + nombre + "</b> - " + plan + "\n   Faltan " + dias + " dias - Vence: " + fecha + "\n   Tel: " + tel);
    inboxLineas.push("[POR VENCER] " + nombre + " - " + plan + " - Faltan " + dias + " dias - " + fecha);
  } else {
    vencidas.push("🔴 <b>" + nombre + "</b> - " + plan + "\n   Vencio hace " + Math.abs(dias) + " dias - Fecha: " + fecha + "\n   Tel: " + tel);
    inboxLineas.push("[VENCIDA] " + nombre + " - " + plan + " - Vencio hace " + Math.abs(dias) + " dias - " + fecha);
  }
}

let msg = "🏋 <b>REPORTE DE VENCIMIENTOS</b>\n" + hoy + "\n";

if (porVencer.length > 0) {
  msg = msg + "\n⚠ <b>POR VENCER - " + porVencer.length + ":</b>\n\n";
  msg = msg + porVencer.join("\n\n");
}

if (vencidas.length > 0) {
  msg = msg + "\n\n🔴 <b>VENCIDAS - " + vencidas.length + ":</b>\n\n";
  msg = msg + vencidas.join("\n\n");
}

msg = msg + "\n\n📊 Total alertas: " + items.length;

const prioridad = vencidas.length > 0 ? "alta" : "media";

return [{
  json: {
    mensaje: msg,
    inbox_tipo: "vencimiento",
    inbox_titulo: "Reporte de vencimientos - " + hoy + " - Por vencer: " + porVencer.length + " / Vencidas: " + vencidas.length,
    inbox_mensaje: inboxLineas.join("\n"),
    inbox_prioridad: prioridad
  }
}];

const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { hay_riesgo: false, telegram: '✅ No hay clientes en riesgo de abandono hoy.', emails: [] } }];
}

const criticos = [];
const medios = [];
const emailsEnviar = [];

for (const item of items) {
  const d = item.json;
  const riesgo = Number(d.riesgo);
  const nombre = d.fullname || 'Cliente';
  const dias = Number(d.dias_sin_pago) || 0;
  const pagos = Number(d.total_pagos) || 0;
  const tel = d.contact || 'Sin tel';
  const correo = d.correo || '';

  const linea = `<b>${nombre}</b> — Riesgo: ${riesgo}% | ${dias} días sin pago | ${pagos} pago(s) | Tel: ${tel}`;

  if (riesgo >= 70) {
    criticos.push(linea);
    // Preparar email personalizado si tiene correo
    if (correo && correo.includes('@')) {
      emailsEnviar.push({
        correo: correo,
        nombre: nombre,
        dias: dias,
        riesgo: riesgo
      });
    }
  } else {
    medios.push(linea);
  }
}

let telegram = `🚨 <b>ALERTA DE ABANDONO</b>\nGym Body Training\n`;

if (criticos.length > 0) {
  telegram += `\n🔴 <b>RIESGO ALTO (${criticos.length}):</b>\n\n` + criticos.join('\n\n');
}

if (medios.length > 0) {
  telegram += `\n\n🟡 <b>RIESGO MEDIO (${medios.length}):</b>\n\n` + medios.join('\n\n');
}

telegram += `\n\n📊 Total en riesgo: ${items.length} | Críticos: ${criticos.length}`;

return [{
  json: {
    hay_riesgo: true,
    telegram: telegram,
    total_riesgo: items.length,
    criticos: criticos.length,
    emails: emailsEnviar,
    inbox_titulo: `Alerta abandono — ${criticos.length} críticos, ${medios.length} medios`,
    inbox_msg: `Clientes en riesgo: ${items.length} total. Críticos: ${criticos.length}. Medios: ${medios.length}.`
  }
}];

const emails = $input.first().json.emails || [];

if (emails.length === 0) {
  return [];
}

return emails.map(e => {
  const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f8f9fa;padding:20px">
  <div style="background:linear-gradient(135deg,#4e73df,#1cc88a);padding:25px 20px;border-radius:12px 12px 0 0;text-align:center">
    <h1 style="color:#fff;margin:0;font-size:22px">🏋️ Gym Body Training</h1>
    <p style="color:rgba(255,255,255,0.9);margin:8px 0 0">¡Te extrañamos!</p>
  </div>
  <div style="background:#fff;padding:25px;border-radius:0 0 12px 12px;border:1px solid #e3e6f0">
    <h2 style="color:#2e3a59;margin-top:0">¡Hola ${e.nombre}! 👋</h2>
    <p style="color:#555;line-height:1.6">Notamos que hace <strong>${e.dias} días</strong> no nos visitas. ¡Queremos verte de vuelta!</p>
    <p style="color:#555;line-height:1.6">Tu salud y bienestar son importantes. El equipo de Gym Body Training te espera con los brazos abiertos. 💪</p>
    <div style="text-align:center;margin:25px 0">
      <span style="background:#1cc88a;color:#fff;padding:12px 30px;border-radius:25px;font-weight:bold;font-size:16px">¡Renueva tu membresía hoy!</span>
    </div>
    <p style="color:#999;font-size:12px;text-align:center">Si ya renovaste, ignora este mensaje.</p>
  </div>
</div>`;

  return { json: { correo: e.correo, nombre: e.nombre, html: html } };
});

const d = $input.first().json;

const actual   = Number(d.ingresos_semana) || 0;
const anterior = Number(d.ingresos_anterior) || 0;
const nuevos   = Number(d.nuevos) || 0;
const activas  = Number(d.activas) || 0;
const porVencer= Number(d.por_vencer) || 0;

// Variación porcentual
let variacion = '';
if (anterior > 0) {
  const pct = (((actual - anterior) / anterior) * 100).toFixed(1);
  variacion = Number(pct) >= 0 ? `(+${pct}% vs semana anterior)` : `(${pct}% vs semana anterior)`;
} else {
  variacion = '(sin datos semana anterior)';
}

// Top planes
const nombre1 = d.nombre || 'N/A';
const ventas1 = d.ventas || 0;

// Fecha rango
const hoy = new Date();
const lunes = new Date(hoy);
lunes.setDate(hoy.getDate() - hoy.getDay() + 1);
const fmt = (dt) => dt.toLocaleDateString('es-BO', { day:'2-digit', month:'2-digit', year:'numeric', timeZone:'America/La_Paz' });

// Telegram (HTML)
const telegram = `📊 <b>REPORTE SEMANAL</b>\nGym Body Training\nSemana del ${fmt(lunes)} al ${fmt(hoy)}\n\n💰 <b>Ingresos:</b> Bs. ${actual.toFixed(2)} ${variacion}\n👥 <b>Clientes nuevos:</b> ${nuevos}\n🏋️ <b>Membresías activas:</b> ${activas}\n⚠️ <b>Por vencer (7 días):</b> ${porVencer}\n\n📈 <b>Plan más vendido del mes:</b>\n   ${nombre1} — ${ventas1} ventas\n\n🔗 Dashboard: http://localhost:3000`;

// Email (HTML rico)
const email = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f8f9fa;padding:20px">
  <div style="background:linear-gradient(135deg,#4e73df,#1cc88a);padding:25px 20px;border-radius:12px 12px 0 0;text-align:center">
    <h1 style="color:#fff;margin:0;font-size:22px">📊 Reporte Semanal</h1>
    <p style="color:rgba(255,255,255,0.9);margin:8px 0 0">Gym Body Training — ${fmt(lunes)} al ${fmt(hoy)}</p>
  </div>
  <div style="background:#fff;padding:25px;border-radius:0 0 12px 12px;border:1px solid #e3e6f0">
    <table style="width:100%;border-collapse:collapse;margin:15px 0">
      <tr><td style="padding:12px 15px;background:#f0f4ff;border:1px solid #dee2e6;font-weight:bold;color:#4e73df">💰 Ingresos</td><td style="padding:12px 15px;border:1px solid #dee2e6;font-size:18px;font-weight:bold">Bs. ${actual.toFixed(2)}</td></tr>
      <tr><td style="padding:12px 15px;background:#f0f4ff;border:1px solid #dee2e6;font-weight:bold;color:#4e73df">📈 Variación</td><td style="padding:12px 15px;border:1px solid #dee2e6">${variacion}</td></tr>
      <tr><td style="padding:12px 15px;background:#f0f4ff;border:1px solid #dee2e6;font-weight:bold;color:#4e73df">👥 Clientes nuevos</td><td style="padding:12px 15px;border:1px solid #dee2e6">${nuevos}</td></tr>
      <tr><td style="padding:12px 15px;background:#f0f4ff;border:1px solid #dee2e6;font-weight:bold;color:#4e73df">🏋️ Membresías activas</td><td style="padding:12px 15px;border:1px solid #dee2e6">${activas}</td></tr>
      <tr><td style="padding:12px 15px;background:#f0f4ff;border:1px solid #dee2e6;font-weight:bold;color:#4e73df">⚠️ Por vencer</td><td style="padding:12px 15px;border:1px solid #dee2e6">${porVencer}</td></tr>
      <tr><td style="padding:12px 15px;background:#f0f4ff;border:1px solid #dee2e6;font-weight:bold;color:#4e73df">🏆 Plan top del mes</td><td style="padding:12px 15px;border:1px solid #dee2e6">${nombre1} (${ventas1} ventas)</td></tr>
    </table>
    <p style="text-align:center;margin:20px 0 5px"><a href="http://localhost:3000" style="background:#4e73df;color:#fff;padding:10px 25px;border-radius:25px;text-decoration:none;font-weight:bold">🔗 Ver Dashboard Completo</a></p>
    <hr style="border:none;border-top:1px solid #e3e6f0;margin:20px 0">
    <p style="color:#999;font-size:12px;text-align:center">Reporte automático — Gym Body Training</p>
  </div>
</div>`;

// Inbox
const inbox_msg = `Ingresos: Bs.${actual.toFixed(2)} ${variacion} | Nuevos: ${nuevos} | Activas: ${activas} | Por vencer: ${porVencer}`;

return [{ json: { telegram, email, inbox_msg, inbox_titulo: `Reporte semanal — ${fmt(lunes)} al ${fmt(hoy)}` } }];

const items = $input.all();

const conteo = { VIP: 0, Regular: 0, Nuevo: 0, Dormido: 0, Perdido: 0, Sin_pagos: 0 };
const detalle = { VIP: [], Regular: [], Nuevo: [], Dormido: [], Perdido: [], Sin_pagos: [] };

for (const item of items) {
  const d = item.json;
  const seg = d.segmento || 'Regular';
  conteo[seg] = (conteo[seg] || 0) + 1;
  if (detalle[seg]) {
    detalle[seg].push(d.fullname);
  }
}

const total = items.length;
const iconos = { VIP: '🌟', Regular: '💪', Nuevo: '🆕', Dormido: '😴', Perdido: '👻', Sin_pagos: '❓' };
const acciones = {
  VIP: 'Premiar lealtad, pedir referidos',
  Regular: 'Mantener comunicación',
  Nuevo: 'Seguimiento a los 15 días',
  Dormido: 'Campaña de reactivación',
  Perdido: 'Oferta agresiva de regreso',
  Sin_pagos: 'Contactar para primer pago'
};

const hoy = new Date().toLocaleDateString('es-BO', { day:'2-digit', month:'2-digit', year:'numeric', timeZone:'America/La_Paz' });

// Telegram
let tg = `📋 <b>SEGMENTACIÓN DE CLIENTES</b>\n${hoy}\n\n`;
for (const seg of ['VIP', 'Regular', 'Nuevo', 'Dormido', 'Perdido', 'Sin_pagos']) {
  if (conteo[seg] > 0) {
    const pct = ((conteo[seg] / total) * 100).toFixed(0);
    tg += `${iconos[seg]} <b>${seg}:</b> ${conteo[seg]} (${pct}%)\n`;
    tg += `   → ${acciones[seg]}\n\n`;
  }
}
tg += `👥 Total clientes: ${total}`;

// Inbox
const inbox_parts = [];
for (const seg of ['VIP','Regular','Nuevo','Dormido','Perdido','Sin_pagos']) {
  if (conteo[seg] > 0) inbox_parts.push(`${seg}: ${conteo[seg]}`);
}

return [{
  json: {
    telegram: tg,
    conteo: conteo,
    total: total,
    inbox_titulo: `Segmentación semanal — ${hoy}`,
    inbox_msg: inbox_parts.join(' | '),
    dormidos: detalle.Dormido || [],
    perdidos: detalle.Perdido || []
  }
}];
